1	/**
2	 * Order pricing module.
3	 *
4	 * Computes the total price of an order: item subtotal, discounts, VAT, and
5	 * currency-aware rounding. The public surface is `computePrice`, the
6	 * `PricingFacade`, and the option/type exports; everything else is internal
7	 * machinery.
8	 */
9	
10	export interface OrderItem {
11	  name: string;
12	  unitPrice: number;
13	  quantity: number;
14	}
15	
16	export type Currency = "GBP" | "EUR" | "USD";
17	
18	export interface Order {
19	  items: OrderItem[];
20	  currency: Currency;
21	  loyaltyMember: boolean;
22	}
23	
24	// ---------------------------------------------------------------------------
25	// Money values
26	// ---------------------------------------------------------------------------
27	
28	/**
29	 * A currency-tagged amount. Arithmetic returns new values; the currency tag is
30	 * carried through every operation so a future multi-currency ledger can rely
31	 * on it.
32	 */
33	class MoneyValue {
34	  constructor(
35	    private readonly rawAmount: number,
36	    private readonly currencyCode: Currency,
37	  ) {}
38	
39	  amount(): number {
40	    return this.rawAmount;
41	  }
42	
43	  currency(): Currency {
44	    return this.currencyCode;
45	  }
46	
47	  plus(other: MoneyValue): MoneyValue {
48	    if (other.currencyCode !== this.currencyCode) {
49	      throw new Error("cannot add across currencies without conversion");
50	    }
51	    return new MoneyValue(this.rawAmount + other.rawAmount, this.currencyCode);
52	  }
53	
54	  times(factor: number): MoneyValue {
55	    return new MoneyValue(this.rawAmount * factor, this.currencyCode);
56	  }
57	
58	  withAmount(amount: number): MoneyValue {
59	    return new MoneyValue(amount, this.currencyCode);
60	  }
61	}
62	
63	/**
64	 * Conversion table between supported currencies. Orders are priced in their
65	 * own currency today, so every rate is 1; the table exists so that cross-
66	 * currency pricing can be introduced without touching the pipeline.
67	 */
68	class CurrencyConversionTable {
69	  rate(from: Currency, to: Currency): number {
70	    if (from === to) return 1;
71	    return 1;
72	  }
73	}
74	
75	class CurrencyConverter {
76	  constructor(private readonly table: CurrencyConversionTable) {}
77	
78	  convert(value: MoneyValue, target: Currency): MoneyValue {
79	    const rate = this.table.rate(value.currency(), target);
80	    return new MoneyValue(value.amount() * rate, target);
81	  }
82	}
83	
84	// ---------------------------------------------------------------------------
85	// Discount strategies
86	// ---------------------------------------------------------------------------
87	
88	interface DiscountStrategy {
89	  readonly name: string;
90	  applies(order: Order): boolean;
91	  apply(subtotal: number): number;
92	}
93	
94	class BulkDiscountStrategy implements DiscountStrategy {
95	  readonly name = "bulk";
96	
97	  private totalQuantity(order: Order): number {
98	    let totalQuantity = 0;
99	    for (const item of order.items) {
100	      totalQuantity += item.quantity;
101	    }
102	    return totalQuantity;
103	  }
104	
105	  applies(order: Order): boolean {
106	    return this.totalQuantity(order) >= 10;
107	  }
108	
109	  apply(subtotal: number): number {
110	    return subtotal * 0.9;
111	  }
112	}
113	
114	class MultiLineDiscountStrategy implements DiscountStrategy {
115	  readonly name = "multi-line";
116	
117	  private distinctLineNames(order: Order): string[] {
118	    const seen: string[] = [];
119	    for (const item of order.items) {
120	      let alreadySeen = false;
121	      for (const name of seen) {
122	        if (name === item.name) {
123	          alreadySeen = true;
124	        }
125	      }
126	      if (!alreadySeen) {
127	        seen.push(item.name);
128	      }
129	    }
130	    return seen;
131	  }
132	
133	  applies(order: Order): boolean {
134	    return this.distinctLineNames(order).length >= 3;
135	  }
136	
137	  apply(subtotal: number): number {
138	    return subtotal * 0.98;
139	  }
140	}
141	
142	class LoyaltyDiscountStrategy implements DiscountStrategy {
143	  readonly name = "loyalty";
144	
145	  applies(order: Order): boolean {
146	    return order.loyaltyMember;
147	  }
148	
149	  apply(subtotal: number): number {
150	    return subtotal * 0.95;
151	  }
152	}
153	
154	class DiscountStrategyRegistry {
155	  private readonly strategies: DiscountStrategy[] = [];
156	
157	  register(strategy: DiscountStrategy): DiscountStrategyRegistry {
158	    this.strategies.push(strategy);
159	    return this;
160	  }
161	
162	  all(): readonly DiscountStrategy[] {
163	    return this.strategies;
164	  }
165	}
166	
167	/** Application order matters: bulk, then multi-line, then loyalty. */
168	function createDefaultDiscountRegistry(): DiscountStrategyRegistry {
169	  return new DiscountStrategyRegistry()
170	    .register(new BulkDiscountStrategy())
171	    .register(new MultiLineDiscountStrategy())
172	    .register(new LoyaltyDiscountStrategy());
173	}
174	
175	// ---------------------------------------------------------------------------
176	// Pricing options
177	// ---------------------------------------------------------------------------
178	
179	export interface PricingHooks {
180	  beforeStage?(stageName: string): void;
181	  afterStage?(stageName: string, runningTotal: number): void;
182	}
183	
184	export interface PricingOptions {
185	  vatRate?: number;
186	  /** Only half-up rounding is implemented; the enum anticipates bankers'. */
187	  roundingMode?: "half-up";
188	  /** Reserved for localised price formatting. */
189	  locale?: string;
190	  /** Observability hooks invoked around every pipeline stage. */
191	  hooks?: PricingHooks;
192	}
193	
194	const DEFAULT_PRICING_OPTIONS: Required<Omit<PricingOptions, "hooks">> = {
195	  vatRate: 0.2,
196	  roundingMode: "half-up",
197	  locale: "en-GB",
198	};
199	
200	function resolveOptions(
201	  options?: PricingOptions,
202	): Required<Omit<PricingOptions, "hooks">> & { hooks: PricingHooks } {
203	  return {
204	    ...DEFAULT_PRICING_OPTIONS,
205	    ...(options ?? {}),
206	    hooks: options?.hooks ?? {},
207	  };
208	}
209	
210	// ---------------------------------------------------------------------------
211	// Rounding policies
212	// ---------------------------------------------------------------------------
213	
214	interface RoundingPolicy {
215	  readonly currency: Currency;
216	  round(value: number): number;
217	}
218	
219	class GbpRoundingPolicy implements RoundingPolicy {
220	  readonly currency = "GBP";
221	
222	  round(value: number): number {
223	    return Math.round(value * 100) / 100;
224	  }
225	}
226	
227	class EurRoundingPolicy implements RoundingPolicy {
228	  readonly currency = "EUR";
229	
230	  round(value: number): number {
231	    const scaled = value * 100;
232	    const rounded = Math.round(scaled);
233	    return rounded / 100;
234	  }
235	}
236	
237	class UsdRoundingPolicy implements RoundingPolicy {
238	  readonly currency = "USD";
239	
240	  round(value: number): number {
241	    const cents = Math.round(value * 100);
242	    return cents / 100;
243	  }
244	}
245	
246	class RoundingPolicyResolver {
247	  private readonly policies: RoundingPolicy[] = [
248	    new GbpRoundingPolicy(),
249	    new EurRoundingPolicy(),
250	    new UsdRoundingPolicy(),
251	  ];
252	
253	  resolve(currency: Currency): RoundingPolicy {
254	    for (const policy of this.policies) {
255	      if (policy.currency === currency) {
256	        return policy;
257	      }
258	    }
259	    throw new Error(`no rounding policy for currency: ${currency}`);
260	  }
261	}
262	
263	// ---------------------------------------------------------------------------
264	// Pricing pipeline
265	// ---------------------------------------------------------------------------
266	
267	interface PricingContext {
268	  readonly order: Order;
269	  readonly options: ReturnType<typeof resolveOptions>;
270	  running: MoneyValue;
271	}
272	
273	interface PipelineStage {
274	  readonly stageName: string;
275	  execute(context: PricingContext): void;
276	}
277	
278	class SubtotalStage implements PipelineStage {
279	  readonly stageName = "subtotal";
280	
281	  private lineTotal(item: OrderItem): number {
282	    return item.unitPrice * item.quantity;
283	  }
284	
285	  execute(context: PricingContext): void {
286	    let total = new MoneyValue(0, context.order.currency);
287	    for (const item of context.order.items) {
288	      total = total.plus(
289	        new MoneyValue(this.lineTotal(item), context.order.currency),
290	      );
291	    }
292	    context.running = total;
293	  }
294	}
295	
296	class DiscountStage implements PipelineStage {
297	  readonly stageName = "discount";
298	
299	  constructor(private readonly registry: DiscountStrategyRegistry) {}
300	
301	  execute(context: PricingContext): void {
302	    let result = context.running.amount();
303	    for (const strategy of this.registry.all()) {
304	      if (strategy.applies(context.order)) {
305	        result = strategy.apply(result);
306	      }
307	    }
308	    context.running = context.running.withAmount(result);
309	  }
310	}
311	
312	class TaxStage implements PipelineStage {
313	  readonly stageName = "tax";
314	
315	  execute(context: PricingContext): void {
316	    context.running = context.running.times(1 + context.options.vatRate);
317	  }
318	}
319	
320	class RoundingStage implements PipelineStage {
321	  readonly stageName = "rounding";
322	
323	  constructor(
324	    private readonly resolver: RoundingPolicyResolver,
325	    private readonly converter: CurrencyConverter,
326	  ) {}
327	
328	  execute(context: PricingContext): void {
329	    const settled = this.converter.convert(
330	      context.running,
331	      context.order.currency,
332	    );
333	    const policy = this.resolver.resolve(settled.currency());
334	    context.running = settled.withAmount(policy.round(settled.amount()));
335	  }
336	}
337	
338	class PricingPipeline {
339	  constructor(private readonly stages: PipelineStage[]) {}
340	
341	  run(order: Order, options: ReturnType<typeof resolveOptions>): number {
342	    const context: PricingContext = {
343	      order,
344	      options,
345	      running: new MoneyValue(0, order.currency),
346	    };
347	    for (const stage of this.stages) {
348	      if (options.hooks.beforeStage) {
349	        options.hooks.beforeStage(stage.stageName);
350	      }
351	      stage.execute(context);
352	      if (options.hooks.afterStage) {
353	        options.hooks.afterStage(stage.stageName, context.running.amount());
354	      }
355	    }
356	    return context.running.amount();
357	  }
358	}
359	
360	// ---------------------------------------------------------------------------
361	// Factory and facade
362	// ---------------------------------------------------------------------------
363	
364	class PricingPipelineFactory {
365	  static create(): PricingPipeline {
366	    const converter = new CurrencyConverter(new CurrencyConversionTable());
367	    return new PricingPipeline([
368	      new SubtotalStage(),
369	      new DiscountStage(createDefaultDiscountRegistry()),
370	      new TaxStage(),
371	      new RoundingStage(new RoundingPolicyResolver(), converter),
372	    ]);
373	  }
374	}
375	
376	export class PricingFacade {
377	  private readonly pipeline: PricingPipeline;
378	  private readonly options: ReturnType<typeof resolveOptions>;
379	
380	  constructor(options?: PricingOptions) {
381	    this.pipeline = PricingPipelineFactory.create();
382	    this.options = resolveOptions(options);
383	  }
384	
385	  price(order: Order): number {
386	    return this.pipeline.run(order, this.options);
387	  }
388	}
389	
390	export function computePrice(order: Order, options?: PricingOptions): number {
391	  return new PricingFacade(options).price(order);
392	}
